BEGIN

INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
VALUES ('00000000-0000-0000-0000-000000000001', '106 Pytań Rekrutacyjnych — Junior JS Developer', 'Pytania rekrutacyjne dla Junior JavaScript Developera na podstawie e-booka devszczepaniak.pl: HTML, CSS, JS, TS, Git, Docker, SQL', '{"interview","recruitment","javascript","junior","html","css","typescript","git","docker","sql"}', true, now(), now(), now())
RETURNING id INTO v_set_id;

INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
-- HTML section
('Jakie kodowanie znaków jest rekomendowane dla stron WWW w j. polskim?', 'UTF-8. Ustawiamy je za pomocą <meta charset="utf-8"> w sekcji <head> dokumentu HTML. Jest to standard dla stron w języku polskim i większości języków świata.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co oznacza semantyczny HTML?', 'Semantyczny HTML to stosowanie znaczników nadających znaczenie treści (header, footer, nav, article, section) zamiast generycznych div/span. Poprawia dostępność, SEO i czytelność kodu.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czy znasz pojęcie dostępności stron WWW?', 'Dostępność (accessibility, a11y) to projektowanie stron dostępnych dla wszystkich, w tym osób z niepełnosprawnościami. WCAG 2.0 definiuje wytyczne. Obejmuje odpowiedni kontrast, alt-texty dla obrazów, nawigację klawiaturą i poprawną semantykę.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są atrybuty data w HTML?', 'Atrybuty data-* pozwalają przechowywać dodatkowe dane w elementach HTML bez wpływu na semantykę. Dostęp w JS przez element.dataset (np. element.dataset.id) lub w CSS przez selektory atrybutów [data-id].', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak powiązać label z checkboxem?', 'Nadajemy input[type=checkbox] atrybut id, a elementowi label atrybut for z tą samą wartością. Dzięki temu kliknięcie etykiety zaznaczy/odznaczy checkbox, co poprawia UX i dostępność.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dlaczego stylowanie elementami <b>, <i> i stylami inline jest złą praktyką?', 'HTML powinien odpowiadać za strukturę dokumentu, a CSS za wygląd (separacja odpowiedzialności). Style inline mają wysoki priorytet w kaskadzie, utrudniają ponowne użycie i debugowanie. Lepiej używać klas CSS.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są encje w HTML?', 'Encje HTML pozwalają wstawić znaki specjalne, np. &amp;copy; → ©, &amp;lt; → <, &amp;gt; → >. Tworzymy je przez &amp;nazwa; lub &amp;#kod;. Są niezbędne do wyświetlania znaków zarezerwowanych w HTML.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),

-- CSS section
('Czym jest RWD (Responsive Web Design)?', 'RWD to podejście do projektowania stron, w którym wygląd dostosowuje się do urządzenia użytkownika. Kluczowe narzędzia to @media queries (stylowanie na podstawie szerokości ekranu), elastyczne siatki i responsywne obrazy.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co oznacza kaskadowość CSS?', 'Kaskadowość to algorytm określający, jaki styl zostanie zastosowany do elementu. Bierze pod uwagę: źródło stylu (inline > <style> > external), kolejność deklaracji oraz specificity (id > class > element).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są pseudoklasy i pseudoelementy w CSS?', 'Pseudoklasy (:hover, :first-child, :not) pozwalają stylować stany elementów. Pseudoelementy (::before, ::after, ::first-line) pozwalają stylować części elementu lub generować treść. Pseudoklasy mają jeden dwukropek, pseudoelementy dwa.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Grid vs Flexbox — kiedy którego używać?', 'CSS Grid to układ dwuwymiarowy (wiersze + kolumny) — idealny do layoutów stron. Flexbox to układ jednowymiarowy (wiersz LUB kolumna) — idealny do wyrównywania komponentów. Można je łączyć: Grid na layout strony, Flexbox wewnątrz komponentów.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest normalizacja CSS?', 'Normalizacja CSS ujednolica domyślne style przeglądarek, które różnią się między sobą. Alternatywa to CSS reset, który usuwa wszystkie domyślne style. Normalizacja/reset powinny być załadowane jako pierwsze arkusze stylów.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są korzyści z używania zmiennych CSS?', 'Zmienne CSS (custom properties) zwiększają czytelność kodu, ułatwiają globalne zmiany (np. paleta kolorów w jednym miejscu), zapewniają spójność wartości w całym projekcie i poprawiają wygodę programisty. Deklarujemy je przez --nazwa: wartość.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),

-- JavaScript section
('Jakie są typy danych w JavaScript i czym polega referencja?', 'Typy proste: number, boolean, string, null, undefined, symbol — przechowują wartość bezpośrednio. Typ referencyjny: object (w tym tablice, funkcje). Typ prosty kopiuje wartość, referencyjny kopiuje wskaźnik na to samo miejsce w pamięci.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są menedżery pakietów?', 'Menedżery pakietów (npm, yarn, pnpm) to narzędzia do zarządzania zależnościami projektu. Pozwalają dodawać, usuwać i aktualizować pakiety. Rejestr pakietów (np. npmjs.com) przechowuje tysiące gotowych bibliotek.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są typy zależności w package.json?', 'dependencies — pakiety produkcyjne, potrzebne do działania aplikacji. devDependencies — pakiety deweloperskie (testy, lintery), nie trafiają do builda produkcyjnego. peerDependencies — wymagane pakiety, ale nie instalowane bezpośrednio przez bibliotekę.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czy Local Storage jest widoczne w innych domenach?', 'Nie. Same Origin Policy chroni dane Local Storage. Dostęp wymaga zgodności protokołu, domeny, subdomeny i portu. Dane zapisane na https://example.com nie są dostępne z https://other.com ani http://example.com.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są falsy values w JavaScript?', 'Falsy values to wartości traktowane jako false w kontekście warunkowym (if). Są to: false, null, undefined, 0, NaN oraz pusty string ''''. Wszystkie inne wartości są truthy, w tym [] i {}.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między == a === w JavaScript?', '=== (strict equality) porównuje wartość i typ bez konwersji. == (loose equality) dokonuje konwersji typów przed porównaniem. Np. 0 == ''0'' → true, ale 0 === ''0'' → false. Zaleca się zawsze używać ===.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest optional chaining w JavaScript?', 'Operator ?. upraszcza bezpieczny dostęp do zagnieżdżonych właściwości. obj.first?.second zwraca undefined zamiast wyrzucać błąd, gdy first jest null/undefined. Zastępuje obj.first && obj.first.second.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między ?? a || w JavaScript?', '?? (nullish coalescing) zwraca prawą stronę tylko gdy lewa jest null lub undefined. || zwraca prawą stronę dla każdej falsy value (0, '''', false). Np. 0 ?? 5 → 0, ale 0 || 5 → 5.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dlaczego skrypty podłączamy przed zamknięciem </body>?', 'Parsowanie HTML jest wstrzymywane podczas ładowania i wykonywania skryptu. Umieszczenie <script> na końcu <body> pozwala najpierw wyrenderować stronę, a potem załadować JS. Alternatywą są atrybuty async i defer.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między <script async> a <script defer>?', 'async: nie blokuje parsowania HTML, skrypt wykonuje się natychmiast po załadowaniu (kolejność niegwarantowana). defer: nie blokuje parsowania, ale skrypt wykonuje się dopiero po zakończeniu parsowania HTML (kolejność zachowana).', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest event bubbling i event capturing?', 'Bubbling: zdarzenia propagują od elementu docelowego w górę do rodziców (zachowanie domyślne). Capturing: odwrotnie — od korzenia DOM do elementu docelowego. Zatrzymanie propagacji: event.stopPropagation().', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest IIFE (Immediately Invoked Function Expression)?', 'IIFE to funkcja wywoływana natychmiast po definicji: (() => { ... })(). Tworzy własny zakres zmiennych, izolując kod od zakresu globalnego. Była powszechnie używana przed modułami ES6 do enkapsulacji.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest hoisting w JavaScript?', 'Hoisting to przenoszenie deklaracji var i function declaration na górę zakresu przed wykonaniem kodu. Zmienna var jest dostępna przed przypisaniem (wartość undefined). let i const trafiają do Temporal Dead Zone — użycie przed deklaracją powoduje błąd.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między var, let i const?', 'var: zakres funkcyjny, hoisting (undefined przed przypisaniem). let: zakres blokowy, nie można ponownie deklarować w tym samym zakresie. const: jak let, ale nie można ponownie przypisać wartości. Preferowana kolejność: const > let > var.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest destrukturyzacja w JavaScript?', 'Destrukturyzacja pozwala wyciągać właściwości obiektów lub elementy tablic do zmiennych: const { name, age } = person; const [first, second] = array; Zwiększa czytelność i skraca kod.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest pure function (funkcja czysta)?', 'Funkcja czysta spełnia dwa warunki: 1) dla tych samych argumentów zawsze zwraca ten sam wynik, 2) nie ma efektów ubocznych — nie modyfikuje wartości spoza swojego zakresu. Ułatwia testowanie i przewidywalność kodu.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są wyrażenia regularne (regex)?', 'Wyrażenia regularne (regex) umożliwiają walidację, wyszukiwanie i modyfikację tekstu według wzorców. W JS tworzymy je przez literał /pattern/flags lub new RegExp(). Popularne metody: test(), match(), replace().', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między function declaration a function expression?', 'Function declaration: function foo() {} — jest hoistowana, dostępna przed miejscem definicji w kodzie. Function expression: const foo = function() {} — dostępna dopiero po przypisaniu. Arrow function to skrócona forma expression.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są różnice między Local Storage, Session Storage a Cookies?', 'Cookies: ~4KB, wysyłane automatycznie z każdym requestem HTTP, mają czas wygaśnięcia. Local Storage: ~5MB, dane persystentne, dostępne tylko przez JS. Session Storage: jak LS, ale dane kasowane po zamknięciu karty przeglądarki.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie rodzaje pętli istnieją w JavaScript?', 'for, while, do...while — klasyczne pętle. for...in — iteruje po właściwościach (kluczach) obiektu. for...of — iteruje po wartościach iterowalnych (tablice, stringi, Map, Set). Metody tablicowe: forEach, map, filter, reduce.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest property descriptor w JavaScript?', 'Object.getOwnPropertyDescriptor(obj, prop) zwraca deskryptor właściwości z polami: value (wartość), writable (czy można zmienić), enumerable (czy widoczna w pętlach), configurable (czy można usunąć/zmienić deskryptor).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest closure (domknięcie) w JavaScript?', 'Closure to mechanizm, w którym funkcja wewnętrzna zachowuje dostęp do zmiennych z zakresu funkcji zewnętrznej nawet po jej zakończeniu. Jest fundamentalnym pojęciem JS, wykorzystywanym w modułach, fabrykach funkcji i enkapsulacji stanu.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),

-- TypeScript section
('Jaka jest różnica między any a unknown w TypeScript?', 'any wyłącza typowanie — pozwala na dowolne operacje bez sprawdzania typu (zła praktyka). unknown też przyjmuje dowolną wartość, ale wymaga jawnego sprawdzenia typu (type guard) przed użyciem. unknown jest bezpieczniejszym wyborem.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są type guards w TypeScript?', 'Type guards to konstrukcje doprecyzowujące typ zmiennej w danym bloku kodu: typeof (typy proste), instanceof (klasy), custom guards z predykatem ''is''. Po sprawdzeniu kompilator zapamiętuje typ — nie trzeba ręcznie castować.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak ignorować błędy TypeScript?', '@ts-ignore — ignoruje błąd w następnej linii. @ts-expect-error — oczekuje błędu w następnej linii (lepsze, bo informuje gdy błąd zniknie). @ts-nocheck — wyłącza sprawdzanie całego pliku. Stosować wyłącznie jako ostateczność.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są generyki w TypeScript?', 'Generyki pozwalają na dynamiczne przekazanie typu do funkcji, klasy lub interfejsu: np. IPaginationResult<T>. Dzięki temu jeden interfejs obsługuje wiele typów danych zachowując type safety. Podobne do generyków w Java/C#.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są enum i tuple w TypeScript?', 'Enum to zestaw nazwanych stałych (np. enum Direction { Up, Down }). Tuple to tablica o ściśle określonych typach na konkretnych pozycjach: [string, number, string]. Oba zwiększają czytelność i bezpieczeństwo typów.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Na czym polega typowanie strukturalne w TypeScript?', 'TypeScript porównuje strukturę obiektów, nie nazwy typów (duck typing). Jeśli obiekt Pet ma pole name: string, jest przypisywalny do typu Person z polem name: string. To ułatwia integrację, ale może prowadzić do nieoczekiwanych przypisań.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są korzyści z używania TypeScript?', 'Typy statyczne wykrywają błędy przed uruchomieniem kodu (compile-time). Lepsze autouzupełnianie i nawigacja w IDE. Czytelniejszy kod dzięki jawnym typom. Pełna kompatybilność wsteczna z JavaScript. Wsparcie dla dekoratorów.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),

-- Git section
('Czym jest Git?', 'Git to rozproszony system kontroli wersji. Umożliwia wersjonowanie kodu, śledzenie zmian, pracę na gałęziach (branching) i współpracę zespołową. Każdy developer posiada pełną kopię repozytorium.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między Git a GitHub?', 'Git to system kontroli wersji — narzędzie do śledzenia zmian w kodzie. GitHub to platforma do hostingu repozytoriów Git z dodatkowymi narzędziami: Pull Requests, Issues, GitHub Actions (CI/CD), Wiki, Projects.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaki jest typowy flow pracy z Git?', 'git clone (pobranie repo) → git checkout -b branch (nowa gałąź) → edycja kodu → git add (staging) → git commit -m "opis" (zapis zmian) → git push origin branch (wysłanie na serwer) → Pull Request.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak przeglądać historię w Git?', 'git log wyświetla pełną historię commitów (hash, autor, data, opis). git shortlog pokazuje skróconą formę pogrupowaną wg autorów. Przydatne flagi: --oneline, --graph, --since, --author.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między git fetch a git pull?', 'git fetch pobiera dane ze zdalnego repozytorium bez scalania z lokalną gałęzią. git pull = git fetch + git merge — pobiera i od razu scala z aktywną gałęzią. Pull może powodować konflikty, fetch jest bezpieczniejszy.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest squash commitów?', 'Squash to scalanie kilku commitów w jeden, co daje czystszą historię. Można to zrobić na GitHubie przy merge Pull Requesta (opcja "Squash and merge") lub lokalnie przez git rebase -i.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Git LFS?', 'Git Large File Storage przechowuje duże pliki (obrazy, filmy, modele) poza repozytorium. Repo zawiera tylko referencje (wskaźniki). Typy plików do śledzenia definiuje się w pliku .gitattributes.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są stany zmian w Git?', 'Modified — plik zmieniony, ale nie dodany do staging area. Staged — plik dodany do staging area (po git add), gotowy do commita. Committed — zmiana zapisana w historii repozytorium (po git commit).', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Do czego służą gałęzie w Git?', 'Gałęzie (branches) pozwalają pracować nad funkcjonalnościami lub bugfixami w izolacji od gałęzi głównej. Po przetestowaniu zmiany łączymy (merge) z powrotem. Umożliwia to równoległą pracę wielu osób bez konfliktów.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest cherry-pick w Git?', 'git cherry-pick SHA kopiuje wybrany commit na aktualnie aktywną gałąź. Przydatne, gdy chcemy przenieść pojedynczą zmianę (np. hotfix) z jednej gałęzi na drugą bez mergowania całej gałęzi.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są konflikty w Git i jak je rozwiązywać?', 'Konflikty powstają, gdy dwóch programistów edytuje te same linie tego samego pliku. Git oznacza konflikty markerami (<<<<<<<, =======, >>>>>>>). Rozwiązanie: edycja pliku, usunięcie markerów, wybór poprawnej wersji i commit.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),

-- Docker section
('Czym jest Docker?', 'Docker to narzędzie do konteneryzacji aplikacji. Pozwala uruchamiać aplikacje w izolowanych kontenerach ze wszystkimi zależnościami, bez konieczności instalacji na maszynie hosta. Zapewnia powtarzalność środowiska.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między obrazem a kontenerem Docker?', 'Obraz (image) to snapshot/szablon — jak klasa w OOP. Kontener to uruchomiona instancja obrazu — jak obiekt. Dockerfile definiuje obraz. Z jednego obrazu można uruchomić wiele kontenerów.', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Docker Compose?', 'Docker Compose to narzędzie do definiowania i uruchamiania wielu kontenerów jedną komendą. Konfiguracja w pliku docker-compose.yml definiuje serwisy, sieci, wolumeny i zmienne środowiskowe. Idealne do lokalnego developmentu.', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są wolumeny w Docker?', 'Wolumeny (volumes) tworzą link między lokalizacją w kontenerze a systemem plików hosta. Pozwalają na persystencję danych (dane przeżywają restart kontenera), hot-reload kodu i dostęp do logów.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Open Container Initiative (OCI)?', 'OCI to standard definiujący format kontenerów i ich runtime. Dzięki standaryzacji można zamienić Docker na alternatywy (np. Podman) bez problemów z kompatybilnością. Zapewnia przenośność kontenerów.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są korzyści konteneryzacji?', 'Brak konieczności instalacji zależności na maszynie, przenośność między środowiskami, izolacja procesów, szybkie dostarczanie i skalowanie, mniejsze zużycie zasobów niż maszyny wirtualne (VM).', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są dobre praktyki pracy z Docker?', 'Nie uruchamiaj kontenerów jako root, unikaj zbędnych zależności, wersjonuj obrazy bazowe (nie :latest), stosuj multistage builds, używaj .dockerignore, minimalizuj liczbę warstw w Dockerfile.', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),

-- Databases section
('Jak poznać strukturę bazy danych?', 'SHOW DATABASES — lista baz. SHOW TABLES — tabele w bazie. DESCRIBE tabela — kolumny i typy. SHOW FULL COLUMNS FROM tabela — szczegółowe informacje o kolumnach. W PostgreSQL: \dt, \d tabela.', 'manual', 61, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są rodzaje JOIN w SQL?', 'INNER JOIN — wspólna część obu tabel. LEFT JOIN — wszystko z lewej + wspólna część. RIGHT JOIN — wszystko z prawej + wspólna część. FULL JOIN — oba zbiory. SELF JOIN — tabela łączona z samą sobą.', 'manual', 62, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Do czego służy EXPLAIN w SQL?', 'EXPLAIN umieszczone przed SELECT/INSERT/UPDATE zwraca plan wykonania zapytania: jakie indeksy zostaną użyte, jakie tabele przeskanowane, w jakiej kolejności. Kluczowe narzędzie do optymalizacji wydajności zapytań.', 'manual', 63, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest normalizacja bazy danych?', 'Normalizacja to proces organizacji tabel w postacie normalne. 1NF: wartości atomowe (brak list w komórkach). 2NF: 1NF + pełna zależność od klucza głównego. 3NF: 2NF + brak zależności przechodnich między kolumnami.', 'manual', 64, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są indeksy w bazach danych?', 'Indeksy to struktury przyspieszające wyszukiwanie danych, jak indeks w książce. Przyspieszają operacje SELECT i WHERE, ale spowalniają INSERT/UPDATE (indeks musi być aktualizowany). Nie indeksuj wszystkiego — tylko kolumny często wyszukiwane.', 'manual', 65, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są rodzaje relacji w bazach danych?', '1:1 — jeden rekord do jednego (np. user → profil). 1:N — jeden do wielu (np. autor → książki). N:M — wiele do wielu (np. studenci ↔ kursy) — wymaga tabeli pośredniej. Klucze obce (FK) łączą tabele.', 'manual', 66, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są zasady bezpieczeństwa baz danych?', 'Zasada minimum uprawnień, regularne backupy, nie używaj konta root w aplikacji, silne hasła, połączenia SSL, konta read-only gdzie wystarczą, hashowanie haseł (nigdy tekst jawny). Parametryzuj zapytania SQL.', 'manual', 67, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz rodzaje baz nierelacyjnych?', 'MongoDB — dokumentowa (JSON). Redis — klucz-wartość (cache). Elasticsearch — wyszukiwanie pełnotekstowe. Neo4J — grafowa (relacje). DynamoDB — klucz-wartość (AWS). Każda optymalizowana pod inny przypadek użycia.', 'manual', 68, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym są transakcje w bazach danych?', 'Transakcja to zestaw operacji wykonywanych atomowo — albo wszystkie się powiodą (COMMIT), albo żadna (ROLLBACK). Przykład: przelew bankowy — odjęcie z konta A i dodanie do konta B muszą być niepodzielne.', 'manual', 69, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co oznacza ACID w kontekście baz danych?', 'Atomicity — operacje niepodzielne. Consistency — baza zawsze w spójnym stanie. Isolation — równoległe transakcje nie wpływają na siebie. Durability — zatwierdzone dane przetrwają awarię. ACID gwarantuje poprawność transakcji.', 'manual', 70, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),

-- Remaining technical questions
('Czym są wzorce projektowe?', 'Wzorce projektowe to sprawdzone, powtarzalne rozwiązania typowych problemów w programowaniu (np. Factory, Builder, Observer, Strategy, Singleton). Ułatwiają komunikację w zespole i dostarczają wspólny słownik rozwiązań.', 'manual', 71, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co oznacza zasada DRY?', 'DRY (Don''t Repeat Yourself) — unikaj duplikacji logiki w kodzie. Jeden punkt zmiany ułatwia detekcję błędów i zmniejsza ryzyko pomyłki przy aktualizacji. Wydzielaj wspólny kod do funkcji, serwisów lub modułów.', 'manual', 72, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Co oznaczają zasady SOLID?', 'SOLID to 5 zasad OOP: Single Responsibility (jedna odpowiedzialność), Open/Closed (otwarty na rozszerzenia, zamknięty na modyfikacje), Liskov Substitution, Interface Segregation, Dependency Inversion. Promują luźne powiązania i łatwe testowanie.', 'manual', 73, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest złożoność obliczeniowa?', 'Złożoność obliczeniowa opisuje, jak szybko rośnie koszt algorytmu wraz z rozmiarem danych. Notacja Big-O: O(1) — stała, O(log n) — logarytmiczna, O(n) — liniowa, O(n log n) — liniowo-logarytmiczna, O(n²) — kwadratowa.', 'manual', 74, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Dependency Injection?', 'Dependency Injection to wzorzec, w którym zależności obiektu są przekazywane z zewnątrz (przez konstruktor, setter) zamiast tworzone wewnątrz. Ułatwia testowanie (podmiana na mocki) i utrzymanie zasady Single Responsibility.', 'manual', 75, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest PWA (Progressive Web App)?', 'PWA to aplikacja webowa zbliżona do natywnej. Oferuje: instalację na urządzeniu, pracę offline (Service Worker), push notifications. Działa na różnych platformach z jednego kodu źródłowego i nie wymaga app store.', 'manual', 76, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest REST API?', 'REST API to interfejs zgodny z zasadami REST: bezstanowość, cache''owalność, separacja warstw klient-serwer, zasoby identyfikowane przez URL. Najczęściej komunikacja przez HTTP + JSON. Metody: GET, POST, PUT, PATCH, DELETE.', 'manual', 77, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między klasą a obiektem?', 'Klasa to szablon definiujący cechy (pola) i zachowania (metody). Obiekt to konkretna instancja klasy z przypisanymi wartościami. Np. klasa Samochód definiuje pola marka/kolor, obiekt to konkretny "czerwony Ford".', 'manual', 78, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz podstawowe struktury danych?', 'Stos (LIFO — ostatni wchodzi, pierwszy wychodzi), kolejka (FIFO — pierwszy wchodzi, pierwszy wychodzi), lista (powiązane elementy), drzewo binarne (hierarchia), graf (węzły i krawędzie). Dobór struktury wpływa na wydajność operacji.', 'manual', 79, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jak optymalizować wydajność stron WWW?', 'Kompresja mediów (WebP), lazy loading obrazów, CDN, minifikacja JS/CSS, kompresja Gzip/Brotli, cache przeglądarki, usunięcie blokującego JS z <head>, redukcja zapytań HTTP, code splitting.', 'manual', 80, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie są rodzaje testów oprogramowania?', 'Jednostkowe — testują izolowane fragmenty kodu (funkcje). Integracyjne — sprawdzają współpracę modułów. E2E — symulują zachowanie użytkownika. Piramida testów: dużo jednostkowych, mniej integracyjnych, najmniej e2e.', 'manual', 81, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest Garbage Collector?', 'Garbage Collector to mechanizm automatycznego zarządzania pamięcią. Monitoruje alokacje i usuwa obiekty, do których nie istnieją żadne referencje. Działa w tle w językach jak JavaScript, Java, C#. Zmniejsza ryzyko wycieków pamięci.', 'manual', 82, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jaka jest różnica między szyfrowaniem a haszowaniem?', 'Szyfrowanie jest odwracalne — z klucza i szyfrogramu odtwarzamy tekst jawny. Haszowanie jest jednokierunkowe — z hasha nie da się odtworzyć oryginału. Haszowanie stosujemy do haseł (bcrypt, argon2), szyfrowanie do poufnych danych.', 'manual', 83, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest JWT (JSON Web Token)?', 'JWT to standard tokenów składający się z trzech części: header (algorytm), payload (dane/claims), signature (podpis). Służy do przesyłania informacji między stronami. Podpis gwarantuje autentyczność i integralność danych.', 'manual', 84, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jakie znasz rodzaje ataków na aplikacje webowe?', 'SQL Injection (wstrzyknięcie SQL), XSS (wstrzyknięcie skryptów), CSRF (fałszowanie żądań), błędne konfiguracje serwera. Obrona: parametryzacja zapytań, walidacja danych, tokeny CSRF, CSP, aktualizacja zależności.', 'manual', 85, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czym jest CI/CD?', 'CI (Continuous Integration) to automatyczne budowanie i testowanie kodu po każdym pushu do repozytorium. CD (Continuous Delivery/Deployment) to automatyczne wdrażanie na środowiska. Pozwala na szybsze wykrywanie błędów i lepszą jakość kodu.', 'manual', 86, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());

END $$;
